Add tests for the `removeDorkDirectory` utility function.

**File:** `packages/shared/src/__tests__/manifest.test.ts` (create if it doesn't exist, or add to existing manifest tests)

Use Vitest with `vi.mock('fs/promises')` to mock filesystem operations:

```typescript
import { describe, it, expect, vi, beforeEach } from 'vitest';
import { removeDorkDirectory } from '../manifest.js';
import fs from 'fs/promises';
import type { Stats } from 'fs';

vi.mock('fs/promises');

describe('removeDorkDirectory', () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  it('deletes .dork directory recursively and returns file list', async () => {
    vi.mocked(fs.stat).mockResolvedValue({ isDirectory: () => true } as Stats);
    vi.mocked(fs.readdir).mockResolvedValue(['agent.json', 'SOUL.md'] as unknown as Awaited<ReturnType<typeof fs.readdir>>);
    vi.mocked(fs.rm).mockResolvedValue(undefined);

    const result = await removeDorkDirectory('/home/user/project');

    expect(fs.stat).toHaveBeenCalledWith('/home/user/project/.dork');
    expect(fs.readdir).toHaveBeenCalledWith('/home/user/project/.dork', { recursive: true });
    expect(fs.rm).toHaveBeenCalledWith('/home/user/project/.dork', { recursive: true, force: true });
    expect(result).toEqual(['.dork/agent.json', '.dork/SOUL.md']);
  });

  it('returns empty array if .dork does not exist', async () => {
    vi.mocked(fs.stat).mockResolvedValue(null as unknown as Stats);

    const result = await removeDorkDirectory('/home/user/project');

    expect(result).toEqual([]);
    expect(fs.rm).not.toHaveBeenCalled();
  });

  it('returns empty array if .dork is not a directory', async () => {
    vi.mocked(fs.stat).mockResolvedValue({ isDirectory: () => false } as Stats);

    const result = await removeDorkDirectory('/home/user/project');

    expect(result).toEqual([]);
    expect(fs.rm).not.toHaveBeenCalled();
  });

  it('returns empty array if stat throws (already removed)', async () => {
    vi.mocked(fs.stat).mockRejectedValue(new Error('ENOENT'));

    const result = await removeDorkDirectory('/home/user/project');

    expect(result).toEqual([]);
    expect(fs.rm).not.toHaveBeenCalled();
  });
});
```

**Acceptance criteria:**
- Tests verify recursive deletion when `.dork` exists
- Tests verify empty array return when `.dork` does not exist
- Tests verify no throw when stat fails (directory already removed)
- Tests verify correct path construction (`.dork` appended to project path)
- Tests verify `fs.rm` called with `{ recursive: true, force: true }`

